{
  "learning_outcomes": [
    {
      "unit_name": "Physical World and Measurement",
      "chapter_name": "Units and Measurements",
      "topic": "Need for measurement, Units of measurement, Systems of units, SI units, significant figures, Determining the uncertainty in result, Dimensions of physical quantities, dimensional analysis and its applications",
      "outcomes": [
        "Understand the need for measurement and systems of units.",
        "Identify fundamental and derived SI units.",
        "Apply rules for significant figures and determine uncertainty in results.",
        "Perform dimensional analysis to check the correctness of physical equations."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Straight Line",
      "topic": "Frame of reference, Motion description using differentiation and integration, Uniform and non-uniform motion, Average speed/velocity, Instantaneous velocity, Velocity-time and position-time graphs, Relations for uniformly accelerated motion (graphical and calculus)",
      "outcomes": [
        "Describe motion in a straight line using frame of reference.",
        "Apply elementary concepts of differentiation and integration to describe motion.",
        "Distinguish between uniform and non-uniform motion.",
        "Interpret velocity-time and position-time graphs."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Plane",
      "topic": "Scalar and vector quantities, Vector operations (addition, subtraction, multiplication by scalar), Position and displacement vectors, Unit vectors, Resolution in a plane, Rectangular components, Scalar and Vector products, Projectile motion, Uniform circular motion",
      "outcomes": [
        "Differentiate between scalar and vector quantities.",
        "Perform vector addition, subtraction, and resolution in a plane.",
        "Analyze projectile motion and uniform circular motion."
      ]
    },
    {
      "unit_name": "Laws of Motion",
      "chapter_name": "Laws of Motion",
      "topic": "Force and Inertia, Newton's Laws, Momentum and Impulse, Conservation of linear momentum, Equilibrium of concurrent forces, Static and kinetic friction, Rolling friction, Lubrication, Centripetal force in uniform circular motion",
      "outcomes": [
        "State and apply Newton's three laws of motion.",
        "Explain the concept of inertia and conservation of linear momentum.",
        "Analyze equilibrium conditions for concurrent forces.",
        "Differentiate between static, kinetic, and rolling friction."
      ]
    },
    {
      "unit_name": "Work, Energy and Power",
      "chapter_name": "Work, Energy and Power",
      "topic": "Work done by constant and variable forces, Kinetic energy, Work-energy theorem, Power, Potential energy (including spring), Conservative vs non-conservative forces, Motion in vertical circle, Elastic and inelastic collisions (1D and 2D)",
      "outcomes": [
        "Calculate work done by constant and variable forces.",
        "Apply the work-energy theorem to solve problems involving kinetic energy.",
        "Differentiate between conservative and non-conservative forces.",
        "Analyze elastic and inelastic collisions."
      ]
    },
    {
      "unit_name": "Motion of System of Particles and Rigid Body",
      "chapter_name": "System of Particles and Rotational Motion",
      "topic": "Centre of mass, Torque and Angular momentum, Conservation of CM motion, Moment of force (Torque), Law of conservation of angular momentum, Equilibrium of rigid bodies, Rigid body rotation equations, Linear vs rotational motions comparison, Moment of inertia, Radius of gyration",
      "outcomes": [
        "Determine the center of mass for systems and rigid bodies.",
        "Apply laws of torque and conservation of angular momentum.",
        "Compare linear motion with rotational motion parameters."
      ]
    },
    {
      "unit_name": "Gravitation",
      "chapter_name": "Gravitation",
      "topic": "Planetary motion and Universal law, Kepler's laws, Acceleration due to gravity (variation with altitude/depth), Gravitational potential energy and potential, Escape speed, Orbital velocity of satellite, Energy of orbiting satellite",
      "outcomes": [
        "State Kepler's laws of planetary motion.",
        "Apply the universal law of gravitation.",
        "Calculate escape speed and orbital velocity."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Solids",
      "topic": "Elasticity and Stress-strain, Hooke's law, Young’s modulus, Bulk modulus, Shear modulus (rigidity), Poisson's ratio, Elastic energy, Applications of elastic behavior",
      "outcomes": [
        "Explain the stress-strain relationship.",
        "Calculate moduli of elasticity (Young's, Bulk, Shear)."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Fluids",
      "topic": "Fluid pressure and flow properties, Pressure due to fluid column, Pascal's law (hydraulic lift/brakes), Viscosity, Stokes' law, Terminal velocity, Streamline/turbulent flow, Critical velocity, Bernoulli's theorem (Torricelli's law/Dynamic lift), Surface tension and energy, Angle of contact",
      "outcomes": [
        "Apply Pascal's law to hydraulic systems.",
        "Analyze fluid dynamics using Bernoulli's theorem.",
        "Explain phenomena related to surface tension."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Thermal Properties of Matter",
      "topic": "Heat, Temperature and Expansion, Specific heat capacity (Cp, Cv), Calorimetry, Change of state (latent heat), Heat transfer modes (Conduction, Convection, Radiation), Thermal conductivity, Blackbody radiation concepts, Wein's displacement Law, Stefan's law",
      "outcomes": [
        "Distinguish between temperature and heat.",
        "Apply laws governing thermal expansion and specific heats.",
        "Analyze different modes of heat transfer."
      ]
    },
    {
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics",
      "topic": "Laws of Thermodynamics, Zeroth law (Temperature), First law (Heat, Work, Internal Energy), Second law, State variables and equation of state, Gaseous processes: Isothermal, Adiabatic, Reversible/Irreversible, Cyclic processes",
      "outcomes": [
        "State the laws of thermodynamics.",
        "Analyze gaseous processes (isothermal, adiabatic).",
        "Apply concepts of internal energy and work in cyclic processes."
      ]
    },
    {
      "unit_name": "Behaviour of Perfect Gases and Kinetic Theory of Gases",
      "chapter_name": "Kinetic Theory",
      "topic": "Perfect gas and Kinetic theory assumptions, Equation of state, Work done in compression, Concept of pressure (kinetic), Temperature interpretation, RMS speed, Degrees of freedom, Law of equipartition of energy, Specific heat capacities, Mean free path, Avogadro's number",
      "outcomes": [
        "Derive the kinetic theory explanation for gas pressure.",
        "Apply the law of equipartition of energy to specific heats."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Oscillations",
      "topic": "Periodic motion and SHM, Time period, Frequency, Displacement as function of time, Simple Harmonic Motion (S.H.M), Uniform circular motion relation to S.H.M, Energy in S.H.M., Kinetic and potential energies, Simple pendulum derivation",
      "outcomes": [
        "Define simple harmonic motion and its characteristics.",
        "Derive the expression for the time period of a simple pendulum."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Waves",
      "topic": "Wave motion concepts, Transverse and longitudinal waves, Speed of travelling wave, Displacement relation for progressive wave, Principle of superposition, Reflection, Standing waves in strings and organ pipes, Fundamental mode and harmonics, Beats",
      "outcomes": [
        "Distinguish between transverse and longitudinal waves.",
        "Apply the principle of superposition to standing waves."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–1: Electric Charges and Fields",
      "topic": "Electric charges, Conservation of charge, Coulomb's law, Superposition principle, Continuous Charge Distribution, Electric field, Dipole Torque, Gauss's Theorem Applications (Wire, Plane, Shell)",
      "outcomes": [
        "Apply Coulomb's law to calculate forces between point charges.",
        "Use Gauss's theorem to find electric fields for symmetric charge distributions."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–2: Electrostatic Potential and Capacitance",
      "topic": "Electric potential, Equipotential surfaces, Electric dipole energy, Dielectrics, Polarization, Capacitors (Series/Parallel), Energy stored in capacitor",
      "outcomes": [
        "Calculate electric potential due to point charges and dipoles.",
        "Analyze the behavior of capacitors with dielectric media."
      ]
    },
    {
      "unit_name": "Unit-II Current Electricity",
      "chapter_name": "Chapter–3: Current Electricity",
      "topic": "Current, Drift Velocity, Ohm's Law, Resistivity/Conductivity, Temperature Dependence of Resistance, Internal Resistance, EMF vs Potential Difference, Kirchhoff's Rules and Wheatstone Bridge",
      "outcomes": [
        "Apply Ohm's law to linear and non-linear circuits.",
        "Use Kirchhoff's rules to solve complex circuit problems."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–4: Moving Charges and Magnetism",
      "topic": "Magnetic Field Concepts, Biot-Savart Law, Ampere's Law Applications (Wire/Solenoid), Force on Moving Charge/Conductor, Torque on Current Loop, Magnetic Dipole Moment, Galvanometer Conversion",
      "outcomes": [
        "Calculate magnetic fields using Biot-Savart and Ampere's laws.",
        "Analyze the motion of charged particles in magnetic fields."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–5: Magnetism and Matter",
      "topic": "Bar Magnets, Solenoids as equivalent magnets, Magnetic properties (Para-, Dia-, Ferro-magnetic), Effect of temperature on magnetic properties",
      "outcomes": [
        "Classify materials based on their magnetic properties."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–6: Electromagnetic Induction",
      "topic": "Faraday's laws, Lenz's Law, Self and mutual induction",
      "outcomes": [
        "Apply Faraday's law to calculate induced EMF."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–7: Alternating Current",
      "topic": "Peak/RMS values, Reactance/Impedance, LCR circuits (phasors), Resonance, Power in AC circuits, Wattless current, Transformers",
      "outcomes": [
        "Analyze series resonance in LCR circuits."
      ]
    },
    {
      "unit_name": "Unit–V Electromagnetic Waves",
      "chapter_name": "Chapter–8: Electromagnetic Waves",
      "topic": "Displacement current, Characteristics of EM waves, Transverse nature (qualitative), Electromagnetic spectrum and uses",
      "outcomes": [
        "Describe the characteristics of electromagnetic waves."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–9: Ray Optics and Optical Instruments",
      "topic": "Reflection, Spherical mirrors, Refraction, Total internal reflection, Lenses (Thin lens formula), Prism, Microscopes and Telescopes",
      "outcomes": [
        "Apply mirror and lens formulas to solve optical problems."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–10: Wave Optics",
      "topic": "Wave front, Huygen's principle, Interference (Young's double slit), Diffraction due to single slit",
      "outcomes": [
        "Explain interference and diffraction phenomena using wave theory."
      ]
    },
    {
      "unit_name": "Unit–VII Dual Nature of Radiation and Matter",
      "chapter_name": "Chapter–11: Dual Nature of Radiation and Matter",
      "topic": "Photoelectric effect, Einstein's equation, Particle nature of light, de-Broglie relation (Matter waves)",
      "outcomes": [
        "Explain the photoelectric effect experimentally."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Chapter–12: Atoms",
      "topic": "Rutherford's model, Bohr model of hydrogen atom, Hydrogen line spectra (qualitative)",
      "outcomes": [
        "Describe the postulates of Bohr's atomic model."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Chapter–13: Nuclei",
      "topic": "Nuclear force, Mass-energy relation, Binding energy per nucleon, Nuclear fission, Nuclear fusion",
      "outcomes": [
        "Explain the concept of binding energy and its variation with mass number."
      ]
    },
    {
      "unit_name": "Unit–IX Electronic Devices",
      "chapter_name": "Chapter–14: Semiconductor Electronics: Materials, Devices and Simple Circuits",
      "topic": "Energy bands (Conductors/Semiconductors/Insulators), p-n junction diode characteristics, Rectifiers",
      "outcomes": [
        "Analyze the I-V characteristics of a semiconductor diode."
      ]
    }
  ]
}
